CREATE TABLE IF NOT EXISTS "Usuario" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"nome" VARCHAR(40) NOT NULL,
	"email" VARCHAR(255) NOT NULL,
	"adm" BOOLEAN NOT NULL,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "produto" (
	"id" SERIAL NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"nome" VARCHAR(75),
	"quantidade" INTEGER,
	"preco" DECIMAL,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "Sistema" (
	"id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"produto_id" INTEGER,
	"usuario_id" INTEGER NOT NULL,
	"data" DATE NOT NULL,
	"hora" TIMESTAMP NOT NULL,
	PRIMARY KEY("id")
);



ALTER TABLE "Usuario"
ADD FOREIGN KEY("id") REFERENCES "Sistema"("usuario_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "produto"
ADD FOREIGN KEY("id") REFERENCES "Sistema"("produto_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;

IF NOT EXISTS (SELECT * FROM "Usuario" WHERE "adm" = true) THEN
